SELECT COUNT(DISTINCT LP.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LP ON LP.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE S.SIGLA_CAMPUS = 'OES' AND LP.ANO = '2021' AND LOWER(LP.TIPO) = LOWER('livro organizado ou edicao') AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%farmacia%' OR LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%farmacia%')